class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        vector<int> result;
        for (int i = 0; i <= 100; ++i) {
            for (int j = 0; i * x + j * y <= bound; ++j) {
                result.push_back(i * x + j * y);
            }
        }
        return result;
    }
};
